    27→import { useFileWatcher } from "@/features/file-browser/hooks/useFileWatcher";
    28→import { WorkspaceHeader } from "@/features/workspace/ui/WorkspaceHeader";
    29→import { ContentTabBar, isTabVisible } from "@/features/workspace/ui/ContentTabBar";
    30→import { PRActions } from "@/features/workspace/ui/PRActions";
    31→import { useSettings } from "@/features/settings/api/settings.queries";
