49→/**
50→ * Collapses PRStatus + GhCliStatus into a single discriminated state.
51→ * The priority ordering ensures that when multiple flags are true
52→ * (e.g., conflicts + CI failing), only the highest-priority state wins.
53→ */
54→export function derivePRActionState(
